module TFlipFlop (  
    input wire clk,  
    input wire T,  
    input wire reset,  
    output reg Q  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            Q <= 0;  
        else if (T)  
            Q <= ~Q;  
    end  
endmodule
